@Transactional
public boolean reserve(String skuId, int qty) {
    for (int attempt = 0; attempt < 3; attempt++) {
        Inventory inv = inventoryRepo.findById(skuId).orElseThrow();
        int available = inv.getTotalQty() - inv.getReservedQty();
        if (available < qty) return false;

        int updated = inventoryRepo.reserveWithVersion(
            skuId, qty, inv.getVersion());

        if (updated > 0) {
            redis.decrBy("inv:" + skuId, qty);
            return true;
        }
        // conflict — retry
    }
    return false; // too many conflicts
}

// Pre-check with Redis (fast path)
public boolean preCheck(String skuId, int qty) {
    Long remaining = redis.execute(new DefaultRedisScript<>(
        "local v = redis.call('DECRBY', KEYS[1], ARGV[1])" +
        "if v < 0 then redis.call('INCRBY', KEYS[1], ARGV[1]) return 0 end" +
        "return 1", Long.class),
        List.of("inv:" + skuId), String.valueOf(qty));
    return remaining != null && remaining == 1L;
}

@Scheduled(fixedDelay = 60_000)
public void releaseExpiredReservations() {
    Instant cutoff = Instant.now().minus(15, MINUTES);
    List<Order> expired = orderRepo
        .findByStatusAndCreatedAtBefore(PENDING_PAYMENT, cutoff);

    for (Order order : expired) {
        inventoryService.release(order.getSkuId(), order.getQty());
        order.setStatus(EXPIRED);
        orderRepo.save(order);
        kafkaTemplate.send("order-events",
            new OrderExpiredEvent(order.getId()));
    }
}
